export function initializeDropZone(dropZoneElement, dotNetHelper) {
    function onDragOver(e) {
        e.preventDefault();
        dropZoneElement.classList.add("drag-over");
    }

    function onDragLeave(e) {
        e.preventDefault();
        dropZoneElement.classList.remove("drag-over");
    }

    function onDrop(e) {
        e.preventDefault();
        dropZoneElement.classList.remove("drag-over");

        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || "unknown" });
        }

        dotNetHelper.invokeMethodAsync("OnFilesDropped", files);
    }

    dropZoneElement.addEventListener("dragover", onDragOver);
    dropZoneElement.addEventListener("dragleave", onDragLeave);
    dropZoneElement.addEventListener("drop", onDrop);

    return {
        dispose: () => {
            dropZoneElement.removeEventListener("dragover", onDragOver);
            dropZoneElement.removeEventListener("dragleave", onDragLeave);
            dropZoneElement.removeEventListener("drop", onDrop);
        }
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone">
    <p class="drop-zone-prompt">Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.IsOversize ? "file-error" : "")">
                @if (entry.IsOversize)
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size), @entry.Info.Type
                        <span class="error-message">Error: file exceeds 10 MB limit</span>
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size), @entry.Info.Type
                    </span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10L * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _dropZoneInstance;

    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/fileDropZone.js");
            _dropZoneInstance = await _module.InvokeAsync<IJSObjectReference>(
                "initializeDropZone", _dropZoneRef, DotNetObjectReference.Create(this));
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<DroppedFileInfo> droppedFiles)
    {
        foreach (var f in droppedFiles)
        {
            var info = new FileInfo(f.Name, f.Size, f.Type);
            _files.Add(new FileEntry(info, f.Size > MaxFileSize));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _files.Where(f => !f.IsOversize).Select(f => f.Info).ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_dropZoneInstance is not null)
        {
            await _dropZoneInstance.InvokeVoidAsync("dispose");
            await _dropZoneInstance.DisposeAsync();
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }

    public record FileInfo(string Name, long Size, string Type);

    // Matches the JS object shape
    public class DroppedFileInfo
    {
        public string Name { get; set; } = "";
        public long Size { get; set; }
        public string Type { get; set; } = "";
    }

    private record FileEntry(FileInfo Info, bool IsOversize);
}

.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 40px;
    text-align: center;
    background-color: #f8f9fa;
    transition: background-color 0.2s, border-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.drop-zone-prompt {
    margin: 0;
    color: #6c757d;
    font-size: 1.1rem;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.error-message {
    color: #dc3545;
    font-size: 0.85rem;
    font-weight: 600;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.75rem;
    cursor: pointer;
    font-size: 0.85rem;
    flex-shrink: 0;
}

.btn-remove:hover {
    background: #dc3545;
    color: #fff;
}

